def magick_convert(svg_path, png_path, size, gravity="center", extent=None):
    """Use ImageMagick to convert SVG to PNG."""
    cmd = ["magick", "-background", "none", "-density", "300", svg_path, "-resize", size]
    if extent:
        cmd += ["-gravity", gravity, "-extent", extent]
    cmd += [png_path]
    subprocess.run(cmd, check=True)


def main():
    os.makedirs(BRAND_DIR, exist_ok=True)

    with tempfile.TemporaryDirectory() as tmpdir:
        # Icon SVG: bold SOLE on dark rounded rect — works on any theme
        icon_svg = os.path.join(tmpdir, "sole_icon.svg")
        with open(icon_svg, "w") as f:
            f.write(SOLE_ICON_SVG)

        # Logo SVG: full SOLE FITNESS on dark rounded rect
        logo_svg = os.path.join(tmpdir, "sole_logo.svg")
        with open(logo_svg, "w") as f:
            f.write(SOLE_LOGO_SVG)

        # icon.png & dark_icon.png: same image, works on both themes
        for name in ("icon.png", "dark_icon.png"):
            path = os.path.join(BRAND_DIR, name)
            magick_convert(icon_svg, path, "256x256")
            print(f"Created {name}")

        # logo.png & dark_logo.png: same image, works on both themes
        for name in ("logo.png", "dark_logo.png"):
            path = os.path.join(BRAND_DIR, name)
            magick_convert(logo_svg, path, "480x")
            print(f"Created {name}")

    print("\nDone! Brand assets in:", BRAND_DIR)


if __name__ == "__main__":
    main()
